import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { writeFileSync, unlinkSync, existsSync } from 'node:fs';
import { loadEnv } from '../env';

const ENV_FILE = '.env.test.wxt';

describe('Env Utils', () => {
  describe('loadEnv', () => {
    beforeEach(() => {
      // Clean up any existing test env file
      if (existsSync(ENV_FILE)) unlinkSync(ENV_FILE);
      // Save the original process.env values
      delete process.env.TEST_VAR;
      delete process.env.TEST_VAR2;
    });

    afterEach(() => {
      if (existsSync(ENV_FILE)) unlinkSync(ENV_FILE);
      delete process.env.TEST_VAR;
      delete process.env.TEST_VAR2;
    });

    it('should set parsed env variables on process.env', () => {
      writeFileSync('.env', 'TEST_VAR=hello\nTEST_VAR2=world\n');
      try {
        loadEnv('development', 'chrome');
        expect(process.env.TEST_VAR).toBe('hello');
        expect(process.env.TEST_VAR2).toBe('world');
      } finally {
        unlinkSync('.env');
      }
    });

    it('should expand variables referencing other variables', () => {
      writeFileSync('.env', 'BASE=world\nTEST_VAR=hello_${BASE}\n');
      try {
        loadEnv('development', 'chrome');
        expect(process.env.TEST_VAR).toBe('hello_world');
      } finally {
        unlinkSync('.env');
      }
    });
  });
});

